contract FundMe{

   
    uint256 public constant MINIMUM_USD = 5 * 10**18;//usd to wei

    function fund() public payable{

       require(msg.value >=MINIMUM_USD, "Minimum 0.01 ETH required");

       // require(msg.value >= MINIMUM_USD,"You must send more than minimum funds");
    }

    function withdraw() public {}

